import React from 'react';
import Navbar from '../../components/common/Navbar';
import Sidebar from '../../components/common/Sidebar';
import Card from '../../components/common/Card';
import LineChart from '../../components/charts/LineChart';
import BarChart from '../../components/charts/BarChart';

const StudentDashboard = () => {
  const userName = localStorage.getItem('userName') || 'Student';

  // Dummy data
  const accuracyData = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Accuracy %',
        data: [65, 70, 68, 75, 72, 78, 80],
        borderColor: 'rgb(59, 130, 246)',
        backgroundColor: 'rgba(59, 130, 246, 0.5)',
      },
    ],
  };

  const topicData = {
    labels: ['Arrays', 'Strings', 'Trees', 'DBMS', 'OS'],
    datasets: [
      {
        label: 'Score %',
        data: [85, 70, 65, 80, 75],
        backgroundColor: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'],
      },
    ],
  };

  const recentActivity = [
    { quiz: 'Arrays Quiz 1', score: '8/10', time: '5 mins', date: '2026-03-09' },
    { quiz: 'Strings Quiz 2', score: '7/10', time: '6 mins', date: '2026-03-08' },
    { quiz: 'Trees Quiz 1', score: '6/10', time: '8 mins', date: '2026-03-07' },
  ];

  return (
    <div className="min-h-screen bg-gray-100">
      <Navbar role="Student" userName={userName} />
      <div className="flex">
        <Sidebar role="student" />
        <main className="flex-1 p-6">
          <h2 className="text-3xl font-bold text-gray-800 mb-6">Welcome, {userName}!</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-6">
            <Card title="Total Quizzes" value="24" icon="📝" color="blue" />
            <Card title="Average Accuracy" value="75%" icon="🎯" color="green" />
            <Card title="Avg Solving Time" value="6.2 min" icon="⏱️" color="yellow" />
            <Card title="Weak Topic" value="Trees" icon="📚" color="red" />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
            <div className="bg-white rounded-lg shadow p-6">
              <LineChart data={accuracyData} title="Accuracy Trend (Last 7 Days)" />
            </div>
            <div className="bg-white rounded-lg shadow p-6">
              <BarChart data={topicData} title="Topic Performance" />
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-xl font-semibold mb-4">Recent Quiz Activity</h3>
              <div className="space-y-3">
                {recentActivity.map((activity, index) => (
                  <div key={index} className="flex justify-between items-center border-b pb-2">
                    <div>
                      <p className="font-semibold">{activity.quiz}</p>
                      <p className="text-sm text-gray-600">{activity.date}</p>
                    </div>
                    <div className="text-right">
                      <p className="font-semibold text-blue-600">{activity.score}</p>
                      <p className="text-sm text-gray-600">{activity.time}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-xl font-semibold mb-4">Recommendations</h3>
              <div className="space-y-3">
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-3">
                  <p className="font-semibold text-yellow-800">Practice Trees</p>
                  <p className="text-sm text-yellow-700">Your accuracy dropped in tree problems</p>
                </div>
                <div className="bg-blue-50 border-l-4 border-blue-400 p-3">
                  <p className="font-semibold text-blue-800">Great Progress in Arrays!</p>
                  <p className="text-sm text-blue-700">Keep up the good work</p>
                </div>
                <div className="bg-green-50 border-l-4 border-green-400 p-3">
                  <p className="font-semibold text-green-800">Improve Speed</p>
                  <p className="text-sm text-green-700">Try solving problems faster</p>
                </div>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default StudentDashboard;
